  1	import * as React from 'react';
  2	import { Workload } from '../../types/Workload';
  3	import { hasMissingSidecar } from 'components/VirtualList/Config';
  4	import { Alert, Card, CardBody, CardHeader, Title, TitleSizes, Tooltip, TooltipPosition } from '@patternfly/react-core';
  5	import { kialiStyle } from 'styles/StyleUtils';
  6	import { Labels } from '../../components/Label/Labels';
  7	import { LocalTime } from '../../components/Time/LocalTime';
  8	import { TextOrLink } from '../../components/Link/TextOrLink';
  9	import { renderAPILogo, renderRuntimeLogo } from '../../components/Logo/Logos';
 10	import * as H from '../../types/Health';
 11	import { KialiIcon } from '../../config/KialiIcon';
 12	import { HealthIndicator } from '../../components/Health/HealthIndicator';
 13	import { isMultiCluster } from '../../config';
 14	import { MissingSidecar } from '../../components/MissingSidecar/MissingSidecar';
 15	import { PFBadge, PFBadges } from '../../components/Pf/PfBadges';
 16	import { MissingLabel } from '../../components/MissingLabel/MissingLabel';
 17	import { WorkloadConfigValidation } from '../../components/Validations/WorkloadConfigValidation';
 18	import { getGVKTypeString, isGVKSupported } from 'utils/IstioConfigUtils';
 19	import { DetailDescription } from '../../components/DetailDescription/DetailDescription';
 20	import { AmbientLabel, tooltipMsgType } from '../../components/Ambient/AmbientLabel';
 21	import { gvkType, validationKey } from '../../types/IstioConfigList';
 22	import { infoStyle } from 'styles/IconStyle';
 23	import { classes } from 'typestyle';
 24	import { renderWaypointSimpleLabel } from '../../components/Ambient/WaypointLabel';
 25	import { getAppLabelName } from 'config/ServerConfig';
 26	
 27	type WorkloadDescriptionProps = {
 28	  health?: H.Health;
 29	  namespace: string;
 30	  workload?: Workload;
 31	};
 32	
 33	const resourceListStyle = kialiStyle({
 34	  display: 'flex',
 35	  $nest: {
 36	    '& > ul > li': {
 37	      display: 'flex',
 38	      $nest: {
 39	        '& span': {
 40	          minWidth: '125px',
 41	          fontWeight: 700
 42	        }
 43	      }
 44	    }
 45	  }
 46	});
 47	
 48	const iconStyle = kialiStyle({
 49	  display: 'inline-block'
 50	});
 51	
 52	const blockElementStyle = kialiStyle({
 53	  display: 'block',
 54	  marginTop: '0.125rem'
 55	});
 56	
 57	const workloadInfoStyle = kialiStyle({
 58	  verticalAlign: '-0.125rem'
 59	});
 60	
 61	const healthIconStyle = kialiStyle({
 62	  marginLeft: '0.5rem',
 63	  verticalAlign: '-0.075rem'
 64	});
 65	
 66	const additionalItemStyle = kialiStyle({
 67	  display: 'flex',
 68	  alignItems: 'center'
 69	});
 70	
 71	const runtimeInfoStyle = kialiStyle({
 72	  display: 'flex',
 73	  alignItems: 'center',
 74	  marginTop: '0.5rem'
 75	});
 76	
 77	export const WorkloadDescription: React.FC<WorkloadDescriptionProps> = (props: WorkloadDescriptionProps) => {
 78	  const workload = props.workload;
 79	  if (!workload) {
 80	    return <>Loading</>;
 81	  }
 82	
 83	  const apps: string[] = [];
 84	  const services: string[] = [];
 85	
 86	  // ignore app links for ambient infra
 87	  if (!workload.isWaypoint && !workload.isZtunnel) {
 88	    const appLabelName = getAppLabelName(workload.labels);
 89	    if (appLabelName) {
 90	      apps.push(workload.labels[appLabelName]);
 91	    }
 92	  }
 93	
 94	  workload.services?.forEach(s => services.push(s.name));
 95	
 96	  const isTemplateLabels =
 97	    [
 98	      getGVKTypeString(gvkType.Deployment),
 99	      getGVKTypeString(gvkType.ReplicaSet),
100	      getGVKTypeString(gvkType.ReplicationController),
101	      getGVKTypeString(gvkType.DeploymentConfig),
102	      getGVKTypeString(gvkType.StatefulSet),
103	      getGVKTypeString(gvkType.WorkloadGroup)
104	    ].indexOf(getGVKTypeString(workload.gvk)) >= 0;
105	
106	  const runtimes = (workload.runtimes ?? []).map(r => r.name).filter(name => name !== '');
107	
108	  const workloadProperties = (
109	    <>
110	      <div key="properties-list" className={resourceListStyle}>
111	        <ul style={{ listStyleType: 'none' }}>
112	          {workload.istioInjectionAnnotation !== undefined && (
113	            <li>
114	              <span>Istio Injection</span>
115	              {String(workload.istioInjectionAnnotation)}
116	            </li>
117	          )}
118	
119	          {!isGVKSupported(workload.gvk) && (
120	            <li>
121	              <span>API Version</span>
122	              {`${workload.gvk.Group}.${workload.gvk.Version}`}
123	            </li>
124	          )}
125	
126	          <li>
127	            <span>Type</span>
128	            {workload.gvk.Kind || 'N/A'}
129	          </li>
130	
131	          <li>
132	            <span>Created</span>
133	            <div style={{ display: 'inline-block' }}>
134	              <LocalTime time={workload.createdAt} />
135	            </div>
136	          </li>
137	
138	          <li>
139	            <span>Version</span>
140	            {workload.resourceVersion}
141	          </li>
142	
143	          {workload.additionalDetails.map((additionalItem, idx) => {
144	            return (
145	              <li key={`additional-details-${idx}`} id={`additional-details-${idx}`}>
146	                <div className={additionalItemStyle}>
147	                  <span>{additionalItem.title}</span>
148	                  {additionalItem.icon && renderAPILogo(additionalItem.icon, undefined, idx)}
149	                </div>
150	                <TextOrLink text={additionalItem.value} urlTruncate={64} />
151	              </li>
152	            );
153	          })}
154	
155	          {runtimes.length > 0 && (
156	            <li id="runtimes">
157	              <div className={runtimeInfoStyle}>
158	                <span>Runtimes</span>
159	                <div style={{ display: 'inline-block' }}>
160	                  {runtimes
161	                    .map((rt, idx) => renderRuntimeLogo(rt, idx))
162	                    .reduce(
163	                      (list: React.ReactNode[], elem) =>
164	                        list.length > 0 ? [...list, <span key="sep"> | </span>, elem] : [elem],
165	                      []
166	                    )}
167	                </div>
168	              </div>
169	            </li>
170	          )}
171	        </ul>
172	      </div>
173	    </>
174	  );
175	
176	  return (
177	    <Card id="WorkloadDescriptionCard" data-test="workload-description-card">
178	      <CardHeader>
179	        <Title headingLevel="h5" size={TitleSizes.lg}>
180	          <div key="service-icon" className={iconStyle}>
181	            <PFBadge badge={PFBadges.Workload} position={TooltipPosition.top} />
182	          </div>
183	
184	          {workload.name}
185	          <Tooltip
186	            position={TooltipPosition.right}
187	            content={<div style={{ textAlign: 'left' }}>{workloadProperties}</div>}
188	          >
189	            <KialiIcon.Info className={classes(infoStyle, workloadInfoStyle)} />
190	          </Tooltip>
191	
192	          <span className={healthIconStyle}>
193	            <HealthIndicator id={workload.name} health={props.health} />
194	          </span>
195	
196	          {hasMissingSidecar(workload) && (
197	            <MissingSidecar
198	              dataTest={`missing-sidecar-badge-for-${workload.name}-workload-in-${props.namespace}-namespace`}
199	              tooltip={true}
200	              className={classes(infoStyle, workloadInfoStyle)}
201	              text=""
202	            />
203	          )}
204	
205	          {workload.isAmbient && !workload.isWaypoint && (
206	            <AmbientLabel
207	              tooltip={tooltipMsgType.workload}
208	              waypoint={workload.waypointWorkloads && workload.waypointWorkloads.length > 0 ? true : false}
209	            />
210	          )}
211	
212	          {(!workload.appLabel || !workload.versionLabel) && !workload.isWaypoint && (
213	            <MissingLabel
214	              missingApp={!workload.appLabel}
215	              missingVersion={!workload.versionLabel}
216	              className={classes(infoStyle, workloadInfoStyle)}
217	              tooltip={true}
218	            />
219	          )}
220	
221	          {workload.isWaypoint && renderWaypointSimpleLabel()}
222	        </Title>
223	
224	        {workload.cluster && isMultiCluster && (
225	          <div key="cluster-icon" className={iconStyle}>
226	            <PFBadge badge={PFBadges.Cluster} position={TooltipPosition.right} /> {workload.cluster}
227	          </div>
228	        )}
229	        {!isGVKSupported(workload.gvk) && (
230	          <Alert
231	            variant="info"
232	            isInline={true}
233	            title="Kiali can only supply limited information for this workload type"
234	            style={{ marginTop: '0.25rem' }}
235	          />
236	        )}
237	        <WorkloadConfigValidation
238	          validations={workload.validations!['workload'][validationKey(workload.name, workload.namespace)]}
239	          namespace={props.namespace}
240	          className={classes(workloadInfoStyle, blockElementStyle)}
241	          iconSize={'md'}
242	          detailed={true}
243	        />
244	      </CardHeader>
245	
246	      <CardBody>
247	        {workload.labels && (
248	          <Labels
249	            labels={workload.labels}
250	            tooltipMessage={isTemplateLabels ? 'Labels defined on the Workload template' : undefined}
251	          />
252	        )}
253	
254	        <DetailDescription
255	          namespace={props.namespace}
256	          apps={apps.length > 0 ? apps : undefined}
257	          services={services}
258	          health={props.health}
259	          cluster={props.workload?.cluster}
260	          isWaypoint={workload.isWaypoint}
261	          waypointWorkloads={!workload.isWaypoint ? workload.waypointWorkloads : []}
262	        />
263	      </CardBody>
264	    </Card>
265	  );
266	};

